import React, { useState } from 'react';
import Login from './pages/Login';

function App() {
    const [user, setUser] = useState(null);

    // Если пользователь не вошел, показываем экран логина
    if (!user) {
        return <Login onLogin={setUser} />;
    }

    // Если вошел — показываем основной контент
    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
            <header style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #ccc', paddingBottom: '10px' }}>
                <span>Вы вошли как: <b>{user.login}</b> ({user.role})</span>
                <button onClick={() => setUser(null)}>Выйти</button>
            </header>

            <main style={{ marginTop: '20px' }}>
                <h2>Выберите этаж</h2>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                    <button style={btnStyle}>3 Этаж (301-348)</button>
                    <button style={btnStyle}>4 Этаж (401-471)</button>
                    <button style={btnStyle}>5 Этаж (501-555)</button>
                </div>

                <button style={{ ...btnStyle, backgroundColor: '#dc3545', marginTop: '30px' }}>
                    Список просрочки
                </button>
            </main>
        </div>
    );
}

const btnStyle = { padding: '20px', fontSize: '18px', borderRadius: '8px', border: 'none', backgroundColor: '#28a745', color: 'white', cursor: 'pointer' };

export default App;
